def rate_limit(limit=app.config['RATE_LIMIT'], timeframe=app.config['RATE_LIMIT_TIMEFRAME']):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            key = request.remote_addr + request.endpoint
            if key not in app.rate_limit_store:
                app.rate_limit_store[key] = []
            app.rate_limit_store[key].append(datetime.now())
            app.rate_limit_store[key] = [x for x in app.rate_limit_store[key] if (datetime.now() - x).total_seconds() < timeframe]
            if len(app.rate_limit_store[key]) > limit:
                return jsonify({'error': 'Rate limit exceeded'}), 429
            return f(*args, **kwargs)
        return decorated_function
    return decorator

